def get_image_adjust(width, height, baseline):
    if width < height:
        height = height / width * baseline
        width = baseline
    else:
        width = width / height * baseline
        height = baseline
    return {'width': width, 'height': height}

def get_image_adjust_large(width, height, baseline):
    if width > height:
        height = height / width * baseline
        width = baseline
    else:
        width = width / height * baseline
        height = baseline
    return {'width': width, 'height': height}

