def add_progress_bar(processing_statement: str, interval_second: int, process_time_estimated: int, loading_bar=None):
    if loading_bar is not None:
        progress_bar = loading_bar.progress(0, text=processing_statement + f" (Expected running time: 0/{str(process_time_estimated)})")
    else:
        progress_bar = st.progress(0, text=processing_statement + f" (Expected running time: 0/{str(process_time_estimated)})")
    running_seconds = 0
    loopCount = 0
    loopLimit = process_time_estimated / interval_second * 10
    while st.session_state.di_apiIsRunning:
        time.sleep(int(interval_second))
        running_seconds = running_seconds + int(interval_second)
        percent_complete = round(running_seconds / process_time_estimated, 2)
        if percent_complete >= 1:
            percent_complete = 0.99
        progress_bar.progress(percent_complete, text=processing_statement + f" (Expected running time: {str(loopCount)}/{str(process_time_estimated)})")
        loopCount += 1
        if loopCount > loopLimit:
            break
    progress_bar.progress(100, text=processing_statement)

