def call_func_with_progress_bar(processing_statement, interval_second, process_time_estimated, func_call, auto_retry=True, loading_bar=None):
    if not auto_retry:
        st.session_state.errCount = 3
    def thread_cfunc_call():
        try:
            callApiWithCheck(func_call)
        except Exception as error:
            print(error)
        st.session_state.di_apiIsRunning = False

    t_func_call  = threading.Thread(target=thread_cfunc_call, args=())
    add_script_run_ctx(t_func_call)
    t_func_call.start()

    add_progress_bar(processing_statement, interval_second, process_time_estimated, loading_bar)

    t_func_call.join()
    time.sleep(1)
    st.rerun()

