def add_lora_select(model_type=None):
    st.write("Custom Model:")

    # 跟踪模弝坘化
    if "previous_model_type" not in st.session_state:
        st.session_state.previous_model_type = model_type

    # 坪在模弝坘化时清空列表
    if model_type != st.session_state.previous_model_type:
        st.session_state.di_input_lora_list = []
        st.session_state.previous_model_type = model_type

    with st.container(border=True):
        if model_type == "dev":
            filtered_list = [lora for lora in st.session_state.user_lora_list if lora.get('lora_model_type') == "dev"]
        else:
            filtered_list = [lora for lora in st.session_state.user_lora_list if lora.get('lora_model_type') == "pro"]

        lora_options = [""] + [f"{lora_data['lora_name']} ({lora_data['lora_id']})" for lora_data in filtered_list]

        def add_lora():
            st.session_state.di_input_lora_list.append({"lora":None,"scale":1.0})
        def remove_lora(idx):
            del st.session_state.di_input_lora_list[idx]
        def update_lora(idx):
            lora_name = st.session_state[f"lora_{idx}"]
            lora_idx = lora_options.index(lora_name) - 1
            if lora_idx < 0:
                st.session_state.di_input_lora_list[idx]["lora"] = None
            else:
                lora = filtered_list[lora_idx]  # 使用过滤坎的列表
                st.session_state.di_input_lora_list[idx]["lora"] = lora

            if f"lora_scale_{idx}" in st.session_state:
                lora_scale = st.session_state[f"lora_scale_{idx}"]
                st.session_state.di_input_lora_list[idx]["scale"] = lora_scale
        for idx, input_lora in enumerate(st.session_state.di_input_lora_list):
            with st.container(border=True):
                lora_idx = 0 if input_lora["lora"] is None else lora_options.index(f"{input_lora['lora']['lora_name']} ({input_lora['lora']['lora_id']})")
                st.selectbox("Custom Model",options=lora_options,label_visibility="collapsed",index=lora_idx,key=f"lora_{idx}", on_change=update_lora, args=(idx,))
                if model_type == "dev":
                    st.slider('Scale',min_value=0.0,max_value=4.0,step=0.1,value=float(input_lora["scale"]), key=f"lora_scale_{idx}", on_change=update_lora, args=(idx,))
                st.button('Remove', key=f"lora_remove_{idx}", on_click=remove_lora, args=(idx,))
        if model_type == "dev":
            st.button('Add Custom Model', on_click=add_lora)
        else:
            st.button('Add Custom Model', on_click=add_lora, disabled=(len(st.session_state.di_input_lora_list) > 0))

