def show_prompt_writer():
    st.html("<span class='big-dialog'></span>")
    col1, col2 = st.columns(2)
    with col1:
        def upload_prompt_img():
            st.session_state.di_gpt_prompt = ""
        prompt_image = st.file_uploader("Take a picture", type=['png', 'jpeg', 'jpg', 'webp', 'jfif'], on_change=upload_prompt_img, key='prompt_image_input_key')
        prompt_image_type = None
        if prompt_image is not None:
            if isinstance(prompt_image, st.runtime.uploaded_file_manager.UploadedFile):
                prompt_image = Image.open(prompt_image)
                prompt_image_type = prompt_image.format
            st.image(prompt_image)
        elif st.session_state.di_ai_image is not None:
            prompt_image = st.session_state.di_ai_image
            prompt_image_type = st.session_state.di_ai_image_type
            st.image(prompt_image)
    with col2:
        gpt_prompt = st.text_area("GPT Prompt:", value="please describe this image", placeholder="Provide a prompt that generates this images", label_visibility="hidden",key="gpt_prompt")
        st.html('<div class="btnR"></div>')
        if st.button("Run"):
            with st.spinner('Please wait for identify'):
                image = prompt_image
                image_format = prompt_image_type
                image_base64_url = "data:image/" + image_format + ";base64," + app_util.image_to_base64_str(image,image_format)

                genaimessages = gpt_prompt
                gpt4vmessages=[
                        {
                            "role": "system",
                            "content": [
                                {"type": "text",
                                "text": "Only answer the question, do not provide any additional information or add any prefix/suffix other than the answer of the original question. Don't use markdown."}
                            ],
                        },
                        {
                            "role": "user",
                            "content": [
                                {"type": "text", "text": genaimessages},
                                {
                                    "type": "image_url",
                                    "image_url": {
                                        "url": image_base64_url
                                    },
                                },
                            ],
                        }
                    ]

                st.session_state.di_gpt_prompt = streamlit_utils.identify_image(image,gpt4vmessages,genaimessages)

        st.write("Suggested Prompt:")
        sug_prompt = st.session_state.di_gpt_prompt
        st.code(st.session_state.di_gpt_prompt, wrap_lines=True)

        if st.button("Copy"):
            components.html("""
            <script>
                let copyBtn = document.createElement('a');
                copyBtn.onclick = function (){
                    parent.navigator.clipboard.writeText("%s").then(function() {{
                    }}, function(err) {{
                        console.error('Async: Could not copy text: ', err);
                    }});
                }
                copyBtn.click();
            </script>
            """% (sug_prompt),height=0)
            time.sleep(0.05)
            st.rerun()

