def resize_aliyun_img(img):
    if img.size[0] > 4096 or img.size[1] > 4096:
        resize = get_image_adjust_large(img.size[0], img.size[1], 4096)
        img = img.resize((int(resize["width"]),int(resize["height"])))
    if img.size[0] < 150 or img.size[1] < 150:
        resize = get_image_adjust(img.size[0], img.size[1], 150)
        img = img.resize((int(resize["width"]),int(resize["height"])))
    return img

