def auto_height_data_editor(data, key, use_container_width=True, row_height=35, min_height=200, max_height=600, **kwargs):
    import pandas as pd

    # 确保 data 是 DataFrame
    if not isinstance(data, pd.DataFrame):
        try:
            df = pd.DataFrame(data)
        except Exception as e:
            st.error(f"Data conversion failed: {e}")
            df = pd.DataFrame()
    else:
        df = data

    # 动思高度计算，针对大針数杮优化
    n_rows = len(df)

    # 对于大針数杮（超过20行），使用分页或滚动
    if n_rows > 20:
        # 使用固定高度，让 Streamlit 处睆滚动
        calculated_height = max_height
        # 添加分页杝示
        # st.info(f"显示 {n_rows} 行数杮，使用滚动查看所有内容")
    else:
        # 尝数杮針使用动思高度
        calculated_height = min(max_height, max(min_height, n_rows * row_height))

    return st.data_editor(
        df,
        key=key,
        use_container_width=use_container_width,
        height=calculated_height,
        **kwargs
    )

