def gen_comfyui_sketch_image(line, rowSetting):
    def thread_target(img_path, model_type):
        try:
            genaimessages_combined = f"description of the clothing only the {model_type} part from a fashion designer's perspective in an unformatted paragraph including tags at the end.. Use detailed tags to describe only the garment, including length, structure, accessories, and location (excluding patterns, embroidery, and printing)"

            gpt4vmessages_combined = [
                {
                    "role": "user",
                    "content": [
                        {"type": "text", "text": genaimessages_combined},
                        {
                            "type": "image_url",
                            "image_url": {
                                "url": img_path
                            },
                        },
                    ],
                }
            ]
            clothes_describe= streamlit_utils.identify_image(img_path, gpt4vmessages_combined, genaimessages_combined)            
            prompt = {
                "image": img_path,
                "image_type": model_type,
