        except Exception as error:
            st.session_state.ide_apiThreadError = error
            print(error)

    st.session_state.ide_apiThreadError = None
    threads = []
    for index in range(attemptImgSize):
        t = threading.Thread(target=thread_target, args=(rowSetting['prompt'],rowSetting['dalle3_style'],rowSetting['dalle3_resolution'],rowSetting['dalle3_quality']))
