def callApiWithCheck(apiCall):
    st.session_state.warnMsg = ''
    st.session_state.apiError = None
    st.session_state.apiThreadError = None
    st.session_state.apiFunc = apiCall
    try:
        apiCall()
        if st.session_state.apiThreadError is not None:
            raise st.session_state.apiThreadError
        st.session_state.errCount = 0
        st.session_state.apiFunc = None
    except Exception as error:
        st.session_state.errCount += 1
        if st.session_state.errCount == 1:
            st.session_state.warnMsg = 'certain error happened, auto retrying'
        elif st.session_state.errCount == 2:
            st.session_state.warnMsg = 'Error, please click button again or retry later'
        else:
            st.session_state.warnMsg = 'Error, please report to LFAICopilot@lifung.com'
            st.session_state.apiError = error

