def zip_file(files, caption_list=None):
    zip_buffer = io.BytesIO()
    with zipfile.ZipFile(zip_buffer, "a", zipfile.ZIP_DEFLATED, False) as zip_file:
        for i, item in enumerate(files):
            file_name = item.name
            item = Image.open(item)
            io_buffer = io.BytesIO()
            item.save(io_buffer, format=item.format)
            data = io_buffer.getvalue()
            dataType = item.format

            zip_file.writestr(file_name, data)

        if caption_list is not None:
            for i, caption in enumerate(caption_list):
                zip_file.writestr(caption["name"], caption["data"])

    return zip_buffer.getvalue()

