def upload_image_azure_blob(img, userEmail):
    # return  f"{azure_util.get_account_url()}/aidesignoutput/d33dbdce-2f21-4e0a-82cd-0652f8a3b843.JPG"
    try:
        img = pil_image_to_byte(img)
    except Exception as error:
        print(error)

    blob_service_client = azure_util.get_blob_service_client()
    container_name = azure_util.get_container_name()

    error_count = 0
    is_succeed = False
    while not is_succeed:
        try:
            img_file_name = userEmail + "/" + str(time.time()) + str(uuid.uuid4()) + ".JPG"

            blob_client = blob_service_client.get_blob_client(container=container_name, blob=img_file_name)
            blob_client.upload_blob(img)
            is_succeed = True
        except Exception as error:
            error_count += 1
            if error_count >= 10:
                raise error

    st.session_state.history_refresh = True
    return f"{azure_util.get_account_url()}/aidesignoutput/{img_file_name}{azure_util.get_blob_url()}"

