def download_videos(history_select_list):
    blob_service_client = azure_util.get_blob_service_client()
    container_name = azure_util.get_container_name()

    zip_buffer = io.BytesIO()
    with zipfile.ZipFile(zip_buffer, "a", zipfile.ZIP_DEFLATED, False) as zip_file:
        st.session_state.download_img_file_list = []
        def thread_target(v_url):
            blob_client = blob_service_client.get_blob_client(container=container_name, blob=v_url)
            st.session_state.download_img_file_list.append({
                "blob_client": blob_client.download_blob().readall(),
                "url": v_url
            })

        threads = []
        for v_url in history_select_list:
            t = threading.Thread(target=thread_target, args=(v_url,))
            threads.append(t)
            add_script_run_ctx(t)
            t.start()

        for t in threads:
            t.join()

        for i, item in enumerate(st.session_state.download_img_file_list):
            dataType = item["url"].split('.')[-1]

            zip_file.writestr(f'video{i + 1}.{dataType}', item["blob_client"])

    components.html(f"""
        <script>
            var newA = document.createElement('a');
            newA.href = "data:text/csv;base64,{base64.b64encode(zip_buffer.getvalue()).decode()}";
            newA.download = "videos.zip";
            newA.click()
        </script>
        """,height=0)
    time.sleep(3)

