def load_history():
    app_util.console_log_start()
    if 'history_refresh' not in st.session_state:
        st.session_state.history_refresh = True
    if 'history_video_refresh' not in st.session_state:
        st.session_state.history_video_refresh = True
    if 'history_run_load_img' not in st.session_state:
        st.session_state.history_run_load_img = False
    if 'history_page' not in st.session_state:
        st.session_state.history_page = 1
    if 'history_blob_image_list' not in st.session_state:
        st.session_state.history_blob_image_list = []
    if 'history_select_list' not in st.session_state:
        st.session_state.history_select_list = set()
    if 'history_select_list_callback' not in st.session_state:
        st.session_state.history_select_list_callback = set()

    def select_page():
        for index in range(page_start, min(page_start + per_page, len(st.session_state.history_blob_image_url))):
            st.session_state.history_select_list.add(index)

    def unselect_all():
        st.session_state.history_select_list.clear()

    def click_download():
        st.session_state.history_select_list_callback = st.session_state.history_select_list.copy()
        st.session_state.history_select_list.clear()

    def click_download_callback():
        with st.spinner(text=f"Please wait for {len(st.session_state.history_select_list_callback)} images zip generation"):
            history_select_list = []
            for item in st.session_state.history_select_list_callback:
                history_select_list.append(st.session_state.history_blob_image_url[item])
            download_file(history_select_list)
            st.session_state.history_select_list_callback.clear()

    def click_remove():
        history_select_list = []
        for item in st.session_state.history_select_list:
            history_select_list.append(st.session_state.history_blob_image_url[item])
        remove_azure_blob(history_select_list)
        for item in st.session_state.history_select_list:
            checkbox_id = f'history_{item}'
            if checkbox_id in st.session_state:
                st.session_state[checkbox_id] = False
        st.session_state.history_refresh = True
        st.session_state.history_select_list.clear()

    if st.session_state.history_refresh:
        st.session_state.history_refresh = False
        refresh_history()
        st.session_state.history_blob_image_list.clear()
    if st.session_state.history_video_refresh:
        st.session_state.history_video_refresh = False
        refresh_video_history()
    if st.session_state.history_blob_image_url:
        st.write("History:")
        row_size = 2
        per_page = 4
        col = 0
        grid = st.columns(row_size)
        max_page = math.ceil(len(st.session_state.history_blob_image_url) / per_page)

        st_img_loading = st.empty()

        page = st.number_input("Page:", min_value=1, max_value=max_page, value=1, step=1, disabled=st.session_state.get("di_apiIsRunning", False))
        page_start = (page - 1) * per_page

        def on_change_checkbox(index):
            isCheck = st.session_state[f'history_{index}']
            if isCheck:
                st.session_state.history_select_list.add(index)
            elif index in st.session_state.history_select_list:
                st.session_state.history_select_list.remove(index)

        @st.fragment(run_every=1)
        def load_history_img():
            if st.session_state.history_run_load_img:
                return
            elif len(st.session_state.history_blob_image_list) == 0 or page != st.session_state.history_page:
                st.session_state.history_run_load_img = True
                st.session_state.history_page = page
                st.session_state.history_blob_image_list.clear()

                def load_image():
                    blob_service_client = azure_util.get_blob_service_client()
                    container_name = azure_util.get_container_name()
                    def thread_target(index, image_url):
                        blob_client = blob_service_client.get_blob_client(container=container_name, blob=image_url)
                        st.session_state.history_blob_image_list[index] = blob_client.download_blob().readall()
                        app_util.add_console_log(f"load_history_img {len(st.session_state.history_blob_image_list)}")

                        # st.session_state.history_blob_image_list[index] = f"{azure_util.get_account_url()}/aidesignoutput/{image_url}{azure_util.get_blob_url()}"

                    threads = []
                    st.session_state.history_blob_image_list = [None] * per_page
                    # for image_url in st.session_state.history_blob_image_url[page_start:page_start + per_page]:
                    for index, image_url in enumerate(st.session_state.history_blob_image_url[page_start:page_start + per_page]):
                        t = threading.Thread(target=thread_target, args=(index, image_url))
                        threads.append(t)
                        add_script_run_ctx(t)
                        t.start()

                    for t in threads:
                        t.join()

                    st.session_state.history_run_load_img = False
                add_script_run_ctx(threading.Thread(target=load_image, args=())).start()
            else:
                st.rerun()

        if st.session_state.history_run_load_img or len(st.session_state.history_blob_image_list) == 0 or page != st.session_state.history_page:
            st_img_loading.write("⏳ Loading Images")
            load_history_img()
        else:
            for index, image_url in enumerate(st.session_state.history_blob_image_list, page_start):
                if image_url is not None:
                    with grid[col]:
                        try:
                            st.image(image_url)
                        except Exception as error:
                            st.image(f"{azure_util.get_account_url()}/aidesignoutput/{st.session_state.history_blob_image_url[index]}{azure_util.get_blob_url()}")

                        st.checkbox("Select", value=(index in st.session_state.history_select_list), on_change=on_change_checkbox, args=(index,), key=f'history_{index}')
                    col = (col + 1) % row_size


        select_btn_col = st.columns(2)
        with select_btn_col[0]:
            st.button('Select page', on_click=select_page)
        with select_btn_col[1]:
            st.button('Unselect all', on_click=unselect_all)

        st.write(f"{len(st.session_state.history_select_list)} images selected")
        btn_col = st.columns(2)
        with btn_col[0]:
            if st.button('Download', on_click=click_download):
                click_download_callback()

        with btn_col[1]:
            st.button('Remove', on_click=click_remove)

