def aad_search_user(search_user_text):
    access_token = get_aad_access_token()
    headers = {
        'Authorization': f'Bearer {access_token}',
        'Content-Type': 'application/json',
        'ConsistencyLevel': 'eventual'
    }
    endpoint = f'https://graph.microsoft.com/v1.0/users?$count=true&$search="displayName:{search_user_text}" OR "mail:{search_user_text}"&$orderBy=displayName&$select=id,displayName,mail'
    response = requests.get(endpoint, headers=headers)
    if response.status_code == 200:
        return response.json()
    else:
        return None

