def adjust_image_dpi(image_data, target_dpi=300, image_format='PNG'):
    """
    调整图片的DPI值

    Args:
        image_data: 图片数据，可以是PIL Image对象、字节数据或base64字符串
        target_dpi: 目标DPI值，默认300
        image_format: 输出图片格式，默认PNG

    Returns:
        bytes: 调整DPI后的图片字节数据
    """
    try:
        # 处理不同类型的输入
        if isinstance(image_data, Image.Image):
            img = image_data
        elif isinstance(image_data, bytes):
            img = Image.open(io.BytesIO(image_data))
        elif isinstance(image_data, str) and image_data.startswith('data:image'):
            # 处理base64 URL
            header, encoded = image_data.split(",", 1)
            image_bytes = base64.b64decode(encoded)
            img = Image.open(io.BytesIO(image_bytes))
        else:
            raise ValueError("Unsupported image data type")

        # 创建输出缓冲区
        output_buffer = io.BytesIO()

        # 保存图片时设置DPI
        if image_format.upper() == 'JPEG':
            img.save(output_buffer, format='JPEG', dpi=(target_dpi, target_dpi), quality=95)
        elif image_format.upper() == 'PNG':
            img.save(output_buffer, format='PNG', dpi=(target_dpi, target_dpi))
        elif image_format.upper() == 'TIFF':
            img.save(output_buffer, format='TIFF', dpi=(target_dpi, target_dpi))
        else:
            # 默认使用PNG格式
            img.save(output_buffer, format='PNG', dpi=(target_dpi, target_dpi))

        output_buffer.seek(0)
        return output_buffer.getvalue()

    except Exception as e:
        print(f"Error adjusting DPI: {str(e)}")
        # 如果出错，返回原始图片数据
        if isinstance(image_data, bytes):
            return image_data
        elif isinstance(image_data, Image.Image):
            output_buffer = io.BytesIO()
            image_data.save(output_buffer, format=image_format)
            output_buffer.seek(0)
            return output_buffer.getvalue()
        else:
            raise e

