def identify_image_gemini(image, genaimessages):
    # model = google_genai.GenerativeModel("gemini-1.5-flash",
    #     generation_config={"max_output_tokens": 2048,"temperature": 0.4,"top_p": 1,"top_k": 32})
    # response = model.generate_content([image, genaimessages])
    client = google_genai.Client(vertexai=True,project="lft-ai",location="us-central1")
    response = client.models.generate_content( model='gemini-1.5-flash', contents=[image, genaimessages],
        config=genai_types.GenerateContentConfig(max_output_tokens=2048,temperature=0.4,top_p=1,top_k=32,),
    )
    gptresponse = response.text
    return re.sub(r'```json\n|\n```$', '', gptresponse, flags=re.MULTILINE)

