def get_tenant_access_token():
    """
    从飞书接口获取app_access_token
    每次调用都重新请求新token，不使用缓存
    """
    # 获取新的token
    url = "https://open.feishu.cn/open-apis/auth/v3/app_access_token/internal"

    payload = {
        "app_id": APP_ID_FOR_TOKEN,
        "app_secret": APP_SECRET
    }

    headers = {
        "Content-Type": "application/json"
    }

    try:
        response = requests.post(url, headers=headers, json=payload)
        result = response.json()

        if response.status_code == 200 and result.get("code") == 0:
            # 获取token成功
            token = result.get("tenant_access_token")
            if not token:
                return None
            return token
        else:
            return None
    except Exception as e:
        return None

def update_feishu_record(score_data):
    """
    将数据记录到飞书多维表格
    使用动态获取的app_access_token进行认证
    """
    # 获取有效的token
    token = get_tenant_access_token()
    if not token:
        return {"error": "无法获取有效的飞书token"}

    url = f"https://open.feishu.cn/open-apis/bitable/v1/apps/{APP_ID}/tables/{BENCH_DATA_TABLE_ID}/records"

