def base64_str_to_image(b64_string: str) -> bytes:
    """
    将 base64 字符串解码为 bytes
    """
    # 如果传入的 base64 字符串包含 data:image/xxx;base64, 前缀，可先剥离
    if "," in b64_string:
        b64_string = b64_string.split(",")[1]
    return base64.b64decode(b64_string)

