def _request_with_retry(method: str, url: str, max_attempts: int = 3, backoff: float = 2.0, **kwargs):
    last_error = None
    for attempt in range(1, max_attempts + 1):
        try:
            response = requests.request(method, url, timeout=120, **kwargs)
            response.raise_for_status()
            return response
        except HTTPError as error:
            last_error = error
            if error.response is not None:
                try:
                    error_data = error.response.json()
                    message = error_data.get("error", {}).get("message") or error_data
                except ValueError:
                    message = error.response.text
                if attempt == max_attempts:
                    raise HTTPError(f"{error} - {message}", response=error.response) from error
            if attempt == max_attempts:
                break
            time.sleep(backoff)
        except RequestException as error:
            last_error = error
            if attempt == max_attempts:
                break
            time.sleep(backoff)
    raise last_error

