def sora_download_video(video_id: str, variant: str = "video") -> bytes:
    response = _request_with_retry(
        "get",
        _build_openai_url(f"/videos/{video_id}/content"),
        headers=_openai_headers(),
        params={"variant": variant},
        stream=True,
        max_attempts=3,
        backoff=2.0,
    )
    data = bytearray()
    for chunk in response.iter_content(chunk_size=1024 * 1024):
        if chunk:
            data.extend(chunk)
    return bytes(data)

