def get_revised_prompt(input_prompt: str, input_images: list[str] = []):
    input_content = [{"type": "input_text", "text": input_prompt}]

    if input_images:
        for input_image in input_images:
            input_content.append(
                {
                    "type": "input_image",
                    # "image_url": f"data:{input_image.type};base64,{base64.b64encode(input_image.getvalue()).decode('utf-8')}",
                    "image_url": input_image,
                }
            )
    input_user_content = [
        {
            "role": "user",
            "content": input_content,
        }
    ]
    revised_prompt = ""

    tools = [{
        "type": "function",
        "name": "image_gen",
        "description": """
        The `image_gen` tool enables image generation from descriptions and editing of existing images based on specific instructions. Use it when:
        - The user requests an image based on a scene description, such as a diagram, portrait, comic, meme, or any other visual.
        - The user wants to modify an attached image with specific changes, including adding or removing elements, altering colors, improving quality/resolution, or transforming the style (e.g., cartoon, oil painting).
        Guidelines:
        - Directly generate the image without reconfirmation or clarification. 
        - Do NOT mention anything related to downloading the image.
        - Do NOT mention anything related to resolution.
        """,
        "parameters": {
            "type": "object",
            "properties": {
                "revised_prompt": {
                    "type": "string",
                    "description": "The prompt for the result"
                }
            },
            "required": [
                "revised_prompt"
            ],
            "additionalProperties": False
        }
    }]
    openai_output = client.responses.create(
        model="gpt-4.1",
        previous_response_id=None,
        input=input_user_content,
        stream=False,
        tools=tools,
        user=st.session_state.userName if st.session_state.userName else NOT_GIVEN
    )

    return json.loads(openai_output.output[0].arguments)["revised_prompt"]

