        "hl": "en",
        "gl": "us",
        "no_cache": True,
    }

    search = GoogleSearch(params)
    results = search.get_dict()

    images = []
    for img in results["visual_matches"]:
        if len(images) >= result_num:
            break
        image_url = img['thumbnail']
        if image_url.startswith('http'):
            images.append({
                'thumbnailUrl': image_url,
                'webSearchUrl': results["search_metadata"]["google_lens_url"],
                'source': img['link'],
            })
    return images

